// Basic input validation
const item = $input.item.json;
const title = item.title || '';
const link = item.link || item.url || item.guid || '';

if (!title || !link) {
  throw new Error('Missing title or link from RSS feed');
}

return {
  json: {
    title: title.trim(),
    link: link.trim(),
    description: (item.description || item.summary || '').substring(0, 500)
  }
};

// Extract article text from HTML
const html = $input.item.json.data || $input.item.json.body || '';
const title = $items('Validate Input')[0].json.title;
const link = $items('Validate Input')[0].json.link;

let content = html;
const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
const mainMatch = html.match(/<main[^>]*>([\s\S]*?)<\/main>/i);

if (articleMatch) content = articleMatch[1];
else if (mainMatch) content = mainMatch[1];

// Strip HTML
content = content.replace(/<script[\s\S]*?<\/script>/gi, '');
content = content.replace(/<style[\s\S]*?<\/style>/gi, '');
content = content.replace(/<[^>]+>/g, ' ');
content = content.replace(/&nbsp;/g, ' ');
content = content.replace(/&amp;/g, '&');
content = content.replace(/\s+/g, ' ').trim();

const fullText = content.substring(0, 3000);

return {
  json: {
    title,
    url: link,
    full_text: fullText
  }
};

