// Parse OpenAI JSON response
const raw = $input.item.json.message?.content || $input.item.json.text || '';
let parsed;
try {
  const cleaned = raw.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse OpenAI response: ' + e.message);
}

const title = $items('Extract Article Text')[0].json.title;
const url = $items('Extract Article Text')[0].json.url;

if (!parsed.twitter_thread) parsed.twitter_thread = ['Check out: ' + title + ' ' + url];
if (!parsed.linkedin_post) parsed.linkedin_post = title + '\n\nRead more: ' + url;

return {
  json: {
    ...parsed,
    title,
    url
  }
};
